var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인은 어렸을 적부터 사부님에게 거두어져 암살훈련을 받으며 자랐소.","JPN":"自分は幼いころ、師匠に引取られ、暗殺訓練を受けながら育ちました。","ENG":"I was taken under my master's wing as a child and was raised as an assassin.","TWN":"在下從小就被師父收留，接受刺客訓練長大。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그리고 오랫동안 흑동이라는 음지의 조직에 몸담아 왔다오.","JPN":"そして、長くにわたり黒東という闇の組織に所属していました。","ENG":"For all this time, I have dwelt within a shadow organization called Black East.","TWN":"並且長期為一個名為黑東的組織效力。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"시엘 양? 잠시만…","JPN":"シエルさん？　ちょっと……","ENG":"Ciel? Hold that thought...","TWN":"希爾同學？你先等一下…"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"지금 하는 얘긴 학생부 기록에 적혀 있지 않은 내용인 것 같은데?","JPN":"今の話は、指導要録に書いてない内容だと思うけど。","ENG":"What you just told me, it's not written anywhere in your school records.","TWN":"你現在說的內容，好像都不在學生資料紀錄表上？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그렇소. 암살자는 목표의 꼬리를 밟되 꼬리를 밟혀선 안 되니까.","JPN":"然様でございます。暗殺者たるもの、標的の尻尾は掴むものであり、掴まれてはなりません。","ENG":"As things should be. An assassin may chase after her target, but should not be caught by one.","TWN":"正是，身為刺客，必須深藏不露，不能讓人逮到把柄。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"이름과 생김새와 행적… 그 무엇도 대외적으로 기록에 남겨선 안된다오.","JPN":"名前と容貌そして活動の痕跡……何一つ外部の記録に残してはいけないのです。","ENG":"One's name, appearance, and behavior... None should be recorded on any material.","TWN":"無論是名字、長相和行蹤…都不能對外留下任何紀錄。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"저기… 지금이 무슨 시간인지 알고 있는 거지?","JPN":"あの……今私たち何をしているのかわかってるよね？","ENG":"Um... You do know what this is, right?","TWN":"同學…你知道現在是什麼時間嗎？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"개인면담은 절대비밀을 보장하며, 선생과 학생이 진솔한 대화를 나누는 시간이라 배웠소.","JPN":"個人面談とは厳格な秘密保持を有し、教師と生徒が率直な対話を交わす時間と教わっています。","ENG":"I learned that personal counseling is time spent between a teacher and student that is confidential and used for open communication.","TWN":"據在下所知，個人諮商是老師與學生一對一的談話時間，而且所有對話內容都不得洩漏出去。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그리고 선생은 학생인 나에게 과거를 물어보았으니 응당 거짓을 말할 수는 없는 것이지.","JPN":"そして自分の過去について質問された以上、無論嘘をつくわけにはいきません。","ENG":"Since you, the teacher, inquired about my past, I am obligated as a student to tell the truth and not to lie.","TWN":"因此在下作為一名學生，當老師問起在下的過去時，當然必須據實以告。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"아니, 그렇긴 한데… 이런 자리에서 갑자기 그런 엄청난 얘길 듣게 될 줄은 몰랐거든.","JPN":"いや、それはそうだけど……ここでいきなりそんなすごい話を聞かされるとは思ってなかったのよね。","ENG":"Yes, that's true, but... I didn't expect to hear something so serious.","TWN":"話是沒錯…但我沒有預料到會聽到這麼震驚的內容。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"어쩔 수 없구려. 비밀을 지키지 못하겠다면 이 자리에서 제거를…","JPN":"仕方ありません。秘密を守れないというなら、この場で抹殺を……","ENG":"Then you leave me no choice. If you cannot keep my secret, then I will have to put an end to you...","TWN":"若是老師無法保守秘密，那在下不得已只好將老師除之…"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"비밀은 지키겠습니다! 무덤까지 가져갈게요! 저주를 받아 무덤에서 좀비로 소생해도 입단속 할게요!","JPN":"秘密は守ります！　お墓まで持っていきます！　もしお墓からゾンビになって蘇っても、口には絶対出しません！","ENG":"I'll keep your secret! I'll take it to my grave! I won't tell a soul, even if I resurrect from the dead and become a zombie!","TWN":"我絕不會說出去！我會把這個秘密帶到墳墓裡！就算因此受到詛咒變成殭屍，我也會把嘴巴管好！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…농담이오.","JPN":"……冗談です。","ENG":"...It was a joke.","TWN":"…在下說笑的。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"아뇨! 분명 엄청난 눈빛으로 노려봤는데요? 저 온몸에 소름이 돋았는데요?","JPN":"いやっ！　確かにものすごい眼差しで睨まれたんですけど？　全身鳥肌立ちましたけど？","ENG":"I don't think so! You were glaring at me! I had chills run down my spine!","TWN":"才不是！你剛才的眼神超認真欸！害我整個起雞皮疙瘩。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그야, 선생의 놀라는 표정을 자세히 보고 싶었거든.","JPN":"それは、先生の驚いた顔をよく見たかったので。","ENG":"That is because I wished for a better look at your astounded expression.","TWN":"那是因為在下想看清楚老師嚇到的樣子。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"너, 눈이 나쁘면 안경을 쓰라고…! 그렇게 눈살 찌푸리면 무섭다니까!","JPN":"目が悪いなら眼鏡をかけなさい……！　あなた、そうやって眉をひそめると怖いのよ！","ENG":"Y-you should wear glasses if you have bad eyesight...! You look so scary when you squint your eyes like that!","TWN":"你視力不好就去配眼鏡…！眼睛睜那麼大是想嚇死誰！"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};